#include <stdio.h>
#include <string.h>
#define OFFSET 10000
#define SIZE 20001

int main() {
    int n, k; scanf("%d %d", &n, &k);
    int a[100001], freq[SIZE];
    memset(freq, 0, sizeof(freq));
    long long count = 0;
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
        int need = k - a[i] + OFFSET;
        if (need >= 0 && need < SIZE) count += freq[need];
        if (a[i] + OFFSET >= 0 && a[i] + OFFSET < SIZE) freq[a[i] + OFFSET]++;
    }
    printf("%lld\n", count);
    return 0;
}

